<template><div class="grid"><section class="galaxy-card metric span3"><p>直播时长</p><strong>{{stats.liveMinutes||0}}m</strong></section><section class="galaxy-card metric span3"><p>TTS次数</p><strong>{{stats.ttsCount||0}}</strong></section><section class="galaxy-card metric span3"><p>平均评分</p><strong>{{stats.avgRating||0}}</strong></section><section class="galaxy-card metric span3"><p>转化率</p><strong>{{stats.conversionRate||'--'}}</strong></section><section class="galaxy-card span6"><h3 class="section-title">观看人数趋势</h3><div class="stat-bars"><div v-for="(v,i) in stats.viewers" :key="i"><p class="muted">第{{i+1}}天 {{v}}</p><div class="bar"><i :style="{width:Math.min(v/6,100)+'%'}"></i></div></div></div></section><section class="galaxy-card span6"><h3 class="section-title">互动数据趋势</h3><div class="stat-bars"><div v-for="(v,i) in stats.interactions" :key="i"><p class="muted">第{{i+1}}天 {{v}}</p><div class="bar"><i :style="{width:Math.min(v/2.2,100)+'%'}"></i></div></div></div></section></div></template>
